outputJsonSchema:
{
  "type": "object",
  "properties": {
    "productName": { "type": "string", "description": "Name of the product" },
    "introduction": { "type": "string", "description": "Overview and purpose of the product" },
    "scope": { "type": "string", "description": "In-scope and out-of-scope features" },
    "targetAudience": { "type": "string", "description": "Who the product is for" },
    "userStories": {
      "type": "array",
      "items": {
        "type": "object",
        "properties": {
          "asA": { "type": "string" },
          "iWantTo": { "type": "string" },
          "soThat": { "type": "string" }
        }
      }
    },
    "functionalRequirements": {
      "type": "array",
      "items": { "type": "string" }
    },
    "nonFunctionalRequirements": {
      "type": "object",
      "properties": {
        "performance": { "type": "string" },
        "scalability": { "type": "string" },
        "security": { "type": "string" },
        "usability": { "type": "string" },
        "reliability": { "type": "string" },
        "maintainability": { "type": "string" },
        "authentication": { "type": "string" },
        "authorization": { "type": "string" },
        "auditingLogging": { "type": "string" },
        "dataPrivacy": { "type": "string" }
      }
    },
    "technicalRequirements": {
      "type": "array",
      "items": { "type": "string" }
    },
    "assumptions": {
      "type": "array",
      "items": { "type": "string" }
    },
    "constraints": {
      "type": "array",
      "items": { "type": "string" }
    }
  },
  "required": [
    "productName", "introduction", "scope", "targetAudience", 
    "userStories", "functionalRequirements", "nonFunctionalRequirements"
  ]
}

outputExample:
{
  "productName": "Example Product",
  "introduction": "This document outlines the requirements for the Example Product, a new web application designed to streamline project management for small teams.",
  "scope": "In-scope: task creation, assignment, status tracking. Out-of-scope: advanced reporting, third-party integrations.",
  "targetAudience": "Small to medium-sized project teams across various industries.",
  "userStories": [
    { "asA": "Project Manager", "iWantTo": "assign tasks to team members", "soThat": "I can delegate work efficiently" }
  ],
  "functionalRequirements": [
    "Users must be able to create new tasks.",
    "Users must be able to update task status."
  ],
  "nonFunctionalRequirements": {
    "performance": "The system shall respond to user actions within 2 seconds under normal load.",
    "security": "All user data shall be encrypted at rest and in transit.",
    "authentication": "Users must authenticate via username and password.",
    "dataPrivacy": "The system must comply with GDPR regulations."
  },
  "technicalRequirements": [
    "The application shall be built using a microservices architecture."
  ],
  "assumptions": [
    "Users have basic computer literacy."
  ],
  "constraints": [
    "The project must be completed within 6 months."
  ]
}
